        if not res:
            return None
        d = 10**9
        for rx, ry in res:
            dd = abs(nx - rx) + abs(ny - ry)
            if dd < d:
                d = dd
        return d

    best_move = (0, 0)
    best_score = -10**18

    for dx, dy in dirs:
        nx, ny = sx + dx, sy + dy
        if not (0 <= nx < w and 0 <= ny < h):
            continue
        if (nx, ny) in obstacles:
            continue
        if (nx, ny) == (ox, oy):
            continue

        dres = best_dist(nx, ny)
        dop = abs(nx - ox) + abs(ny - oy)
        if dres is None:
            dres = 10**6
        score = (-dres * 10) + (dop * 0.3)
        if score > best_score:
            best_score = score
            best_move = (dx, dy)

    dx, dy = best_move
    return [int(dx), int(dy)]

